using ContosoUniversity.Data;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestDbContextHelper
    {
        public static SchoolContext CreateContext(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }
    }
}

using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PersonTests
    {
        // Student inherits Person, so we use it to test the abstract class
        [Fact]
        public void FullName_ReturnsLastNameCommaFirstName()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John"
            };

            Assert.Equal("Smith, John", student.FullName);
        }

        [Fact]
        public void FullName_WithEmptyFirstName_ReturnsLastNameComma()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = ""
            };

            Assert.Equal("Smith, ", student.FullName);
        }

        [Fact]
        public void FullName_WithEmptyLastName_ReturnsCommaFirstName()
        {
            var student = new Student
            {
                LastName = "",
                FirstMidName = "John"
            };

            Assert.Equal(", John", student.FullName);
        }

        [Theory]
        [InlineData("Doe", "Jane", "Doe, Jane")]
        [InlineData("O'Brien", "Conan", "O'Brien, Conan")]
        [InlineData("Van Der Berg", "Anna", "Van Der Berg, Anna")]
        public void FullName_VariousNames_ReturnsExpectedFormat(string lastName, string firstName, string expected)
        {
            var instructor = new Instructor
            {
                LastName = lastName,
                FirstMidName = firstName
            };

            Assert.Equal(expected, instructor.FullName);
        }

        [Fact]
        public void Student_HasEnrollmentDate()
        {
            var date = new DateTime(2023, 9, 1);
            var student = new Student { EnrollmentDate = date };
            Assert.Equal(date, student.EnrollmentDate);
        }

        [Fact]
