using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndex()
        {
            var items = new List<string> { "a", "b" };
            var list = new PaginatedList<string>(items, 10, 2, 5);

            Assert.Equal(2, list.PageIndex);
        }

        [Fact]
        public void Constructor_CalculatesTotalPages()
        {
            var items = new List<string> { "a" };
            var list = new PaginatedList<string>(items, 10, 1, 3);

            // 10 items / 3 per page = 4 pages (ceiling)
            Assert.Equal(4, list.TotalPages);
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<string> { "a", "b", "c" };
            var list = new PaginatedList<string>(items, 10, 1, 5);

            Assert.Equal(3, list.Count);
            Assert.Contains("a", list);
            Assert.Contains("b", list);
            Assert.Contains("c", list);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var list = new PaginatedList<string>(new List<string>(), 10, 1, 5);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var list = new PaginatedList<string>(new List<string>(), 10, 2, 5);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var list = new PaginatedList<string>(new List<string>(), 10, 2, 5);
            // TotalPages = ceil(10/5) = 2, PageIndex = 2
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_FirstPage_ReturnsTrue()
        {
            var list = new PaginatedList<string>(new List<string>(), 10, 1, 5);
            Assert.True(list.HasNextPage);
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(5, result.Count);
            Assert.Equal(6, result[0]); // Items 6-10 on page 2
            Assert.Equal(10, result[4]);
            Assert.Equal(2, result.PageIndex);
            Assert.Equal(4, result.TotalPages); // 20/5 = 4
        }

        [Fact]
        public void Create_FirstPage_HasCorrectItems()
        {
            var source = Enumerable.Range(1, 15).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(5, result.Count);
            Assert.Equal(1, result[0]);
            Assert.Equal(5, result[4]);
        }

        [Fact]
        public void Create_LastPage_MayHaveFewerItems()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();
            var result = PaginatedList<int>.Create(source, 3, 5);

            Assert.Equal(2, result.Count); // Only 2 items on last page
            Assert.Equal(11, result[0]);
            Assert.Equal(12, result[1]);
        }

        [Theory]
        [InlineData(10, 3, 4)] // ceil(10/3) = 4
        [InlineData(1, 1, 1)]
        [InlineData(0, 5, 0)]
        [InlineData(5, 5, 1)]
        [InlineData(6, 5, 2)]
        [InlineData(100, 10, 10)]
        public void TotalPages_CalculatedCorrectly(int totalCount, int pageSize, int expectedPages)
        {
            var items = new List<int>();
            var list = new PaginatedList<int>(items, totalCount, 1, pageSize);

            Assert.Equal(expectedPages, list.TotalPages);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = new List<string>().AsQueryable();
            var result = PaginatedList<string>.Create(source, 1, 10);

            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
            Assert.Equal(1, result.PageIndex);
        }

        [Fact]
        public void HasPreviousPage_And_HasNextPage_MiddlePage()
        {
            var list = new PaginatedList<int>(new List<int>(), 30, 2, 10);
            // TotalPages = 3, PageIndex = 2

            Assert.True(list.HasPreviousPage);
            Assert.True(list.HasNextPage);
        }
    }
}

