using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class HomeControllerTests
    {
        private SchoolContext CreateContextWithStudents()
        {
            var context = TestDbContextHelper.CreateContext();
            context.Students.AddRange(
                new Student { LastName = "A", FirstMidName = "X", EnrollmentDate = new DateTime(2023, 9, 1) },
                new Student { LastName = "B", FirstMidName = "Y", EnrollmentDate = new DateTime(2023, 9, 1) },
                new Student { LastName = "C", FirstMidName = "Z", EnrollmentDate = new DateTime(2024, 1, 15) }
            );
            context.SaveChanges();
            return context;
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            using var context = TestDbContextHelper.CreateContext();
            var controller = new HomeController(context);

            var result = controller.Index();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_ReturnsViewWithEnrollmentDateGroups()
        {
            using var context = CreateContextWithStudents();
            var controller = new HomeController(context);

            var result = controller.About();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(viewResult.Model);
            Assert.Equal(2, model.Count); // Two distinct dates
        }

        [Fact]
        public void About_GroupsStudentsByDate()
        {
            using var context = CreateContextWithStudents();
            var controller = new HomeController(context);

            var result = controller.About();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(viewResult.Model);

            var sept2023Group = model.FirstOrDefault(g => g.EnrollmentDate == new DateTime(2023, 9, 1));
            Assert.NotNull(sept2023Group);
            Assert.Equal(2, sept2023Group.StudentCount);

            var jan2024Group = model.FirstOrDefault(g => g.EnrollmentDate == new DateTime(2024, 1, 15));
            Assert.NotNull(jan2024Group);
            Assert.Equal(1, jan2024Group.StudentCount);
        }

        [Fact]
        public void About_NoStudents_ReturnsEmptyList()
        {
            using var context = TestDbContextHelper.CreateContext();
            var controller = new HomeController(context);

            var result = controller.About();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(viewResult.Model);
            Assert.Empty(model);
        }

        [Fact]
        public void Contact_ReturnsViewResult()
        {
            using var context = TestDbContextHelper.CreateContext();
            var controller = new HomeController(context);

            var result = controller.Contact();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal("Your contact page.", controller.ViewBag.Message);
        }

        [Fact]
        public void Error_ReturnsViewResult()
        {
            using var context = TestDbContextHelper.CreateContext();
            var controller = new HomeController(context);

            var result = controller.Error();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Unauthorized_ReturnsViewWithMessage()
        {
            using var context = TestDbContextHelper.CreateContext();
            var controller = new HomeController(context);

            var result = controller.Unauthorized();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal("You don't have permission to access this resource.", controller.ViewBag.Message);
        }
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests
    {
        private SchoolContext CreateSeededContext()
        {
            var context = TestDbContextHelper.CreateContext();
            context.Students.AddRange(
                new Student { LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2021, 9, 1) },
                new Student { LastName = "Baker", FirstMidName = "Arturo", EnrollmentDate = new DateTime(2022, 9, 1) },
                new Student { LastName = "Zimmerman", FirstMidName = "Laura", EnrollmentDate = new DateTime(2023, 9, 1) }
            );
            context.SaveChanges();
            return context;
        }

        // Index tests
        [Fact]
        public void Index_ReturnsViewWithPaginatedStudents()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(4, model.Count);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAsc()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Alexander", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Baker", model[2].LastName);
            Assert.Equal("Zimmerman", model[3].LastName);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDesc()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Index("name_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Zimmerman", model[0].LastName);
            Assert.Equal("Baker", model[1].LastName);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAsc()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Index("Date", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDesc()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Index("date_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Zimmerman", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByLastName_FiltersResults()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, "Baker", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
            Assert.Equal("Baker", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersResults()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, "Carson", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchResetPage_SetsPageToOne()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, "Baker", 5);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_CurrentFilter_UsedWhenSearchStringNull()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            var result = controller.Index(null, "Baker", null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagSortParameters()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            controller.Index(null, null, null, null);

            Assert.Equal("name_desc", (string)controller.ViewBag.NameSortParm);
            Assert.Equal("Date", (string)controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_WithNameDescSort_SetsEmptyNameSortParm()
        {
            using var context = CreateSeededContext();
            var controller = new StudentsController(context);

            controller.Index("name_desc", null, null, null);

            Assert.Equal("", (string)controller.ViewBag.NameSortParm);
        }

        [Fact]
