        [Fact]
        public void Create_POST_FileTooLarge_ReturnsViewWithError()
        {
            using var context = CreateSeededContext();
            var controller = new CoursesController(context, _mockEnv.Object, _mockLogger.Object);
            var course = new Course { CourseID = 3000, Title = "Course", Credits = 4, DepartmentID = 1 };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("image.jpg");
            mockFile.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB > 5MB limit

            var result = controller.Create(course, mockFile.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(controller.ModelState.ContainsKey("teachingMaterialImage"));
            var errors = controller.ModelState["teachingMaterialImage"].Errors;
            Assert.Contains(errors, e => e.ErrorMessage.Contains("5MB"));
        }

        [Theory]
        [InlineData("image.jpg")]
        [InlineData("image.jpeg")]
        [InlineData("image.png")]
        [InlineData("image.gif")]
        [InlineData("image.bmp")]
        public void Create_POST_ValidExtensions_AcceptsFile(string fileName)
        {
            using var context = CreateSeededContext();
            var controller = new CoursesController(context, _mockEnv.Object, _mockLogger.Object);
            var course = new Course { CourseID = 3000 + fileName.GetHashCode() % 1000, Title = "Course", Credits = 4, DepartmentID = 1 };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns(fileName);
            mockFile.Setup(f => f.Length).Returns(1024);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()));

            var result = controller.Create(course, mockFile.Object);

            // Should either redirect (success) or have an error but NOT the extension error
            if (result is ViewResult)
            {
                // If it returned a view, the error should NOT be about extension
                if (controller.ModelState.ContainsKey("teachingMaterialImage"))
                {
                    var errors = controller.ModelState["teachingMaterialImage"].Errors;
                    Assert.DoesNotContain(errors, e => e.ErrorMessage.Contains("valid image file"));
                }
            }
        }

