+
+namespace ContosoUniversity.Tests.Controllers
+{
+    public class NotificationsControllerTests : IDisposable
+    {
+        public NotificationsControllerTests()
+        {
+            // Drain static queue before each test
+            var service = new NotificationService();
+            while (service.ReceiveNotification() != null) { }
+            service.Dispose();
+        }
+
+        public void Dispose()
+        {
+            // Drain static queue after each test
+            var service = new NotificationService();
+            while (service.ReceiveNotification() != null) { }
+            service.Dispose();
+        }
+
+        [Fact]
+        public void GetNotifications_EmptyQueue_ReturnsEmptyList()
+        {
+            using var context = TestDbContextHelper.CreateContext();
+            var controller = new NotificationsController(context);
+
+            var result = controller.GetNotifications();
+
+            Assert.IsType<JsonResult>(result);
+            var value = result.Value;
+            // Use reflection to check dynamic properties
+            var successProp = value.GetType().GetProperty("success");
+            Assert.True((bool)successProp.GetValue(value));
+            var countProp = value.GetType().GetProperty("count");
+            Assert.Equal(0, (int)countProp.GetValue(value));
+        }
+
+        [Fact]
+        public void GetNotifications_WithNotifications_ReturnsUpTo10()
+        {
+            using var context = TestDbContextHelper.CreateContext();
+
+            // Enqueue notifications via a service
+            var service = new NotificationService();
+            for (int i = 0; i < 15; i++)
+            {
+                service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
+            }
+            service.Dispose();
+
+            var controller = new NotificationsController(context);
+
+            var result = controller.GetNotifications();
+
+            Assert.IsType<JsonResult>(result);
+            var value = result.Value;
+            var countProp = value.GetType().GetProperty("count");
+            var count = (int)countProp.GetValue(value);
+            Assert.True(count <= 10);
+
+            var notificationsProp = value.GetType().GetProperty("notifications");
+            var notifications = notificationsProp.GetValue(value) as List<Notification>;
+            Assert.NotNull(notifications);
+            Assert.True(notifications.Count <= 10);
+        }
+
+        [Fact]
+        public void GetNotifications_DrainsQueueUpTo10()
+        {
+            using var context = TestDbContextHelper.CreateContext();
+
+            var service = new NotificationService();
+            for (int i = 0; i < 5; i++)
+            {
+                service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
+            }
+            service.Dispose();
+
+            var controller = new NotificationsController(context);
+
+            var result = controller.GetNotifications();
+
+            var value = result.Value;
+            var countProp = value.GetType().GetProperty("count");
+            Assert.Equal(5, (int)countProp.GetValue(value));
+        }
